import { Router } from 'express';
import { Prisma } from '@prisma/client';
import { prisma } from './prisma-client';

export const articles = Router();

// articles is a wide table: body_html and raw_markdown together average
// ~250 KB per row. Anything returning more than a handful of rows must
// project explicit columns.

interface ArticleSummary {
  id: string;
  title: string;
  slug: string;
  published_at: Date;
}

// GET /articles/recent — the ten most recent published articles.
articles.get('/articles/recent', async (_req, res) => {
  const rows = await prisma.$queryRaw<ArticleSummary[]>(Prisma.sql`
    SELECT id, title, slug, published_at
    FROM articles
    WHERE status = 'published'
    ORDER BY published_at DESC
    FETCH FIRST 10 ROWS ONLY
  `);
  return res.json({ rows });
});

// GET /articles/:slug — full article body for the reader view.
articles.get('/articles/:slug', async (req, res) => {
  const article = await prisma.article.findUnique({ where: { slug: req.params.slug } });
  if (!article) {
    return res.status(404).json({ message: 'unknown article' });
  }
  return res.json(article);
});

