import { Router } from 'express';
import { prisma } from './prisma-client';

export const audit = Router();

interface AuditFeed {
  events: unknown[];
  nextToken: string | null;
}

// audit_events grows by roughly 50k rows per day for a large org and is
// retained for 180 days, so org histories run into the millions of rows.
audit.get('/orgs/:orgId/audit-events', async (req, res) => {
  const take = Math.min(Number(req.query.take ?? 50) || 50, 200);
  const cursor = typeof req.query.cursor === 'string' ? req.query.cursor : undefined;
  const events = await prisma.auditEvent.findMany({
    where: { orgId: req.params.orgId },
    orderBy: { createdAt: 'desc' },
    take: take + 1,
    ...(cursor ? { cursor: { id: cursor }, skip: 1 } : {}),
  });
  const hasMore = events.length > take;
  const visible = hasMore ? events.slice(0, take) : events;
  const body: AuditFeed = {
    events: visible,
    nextToken: hasMore ? visible[visible.length - 1].id : null,
  };
  return res.json(body);
});

// GET /orgs/:orgId/audit-events/:id — one event, for the detail drawer.
audit.get('/orgs/:orgId/audit-events/:id', async (req, res) => {
  const event = await prisma.auditEvent.findUnique({ where: { id: req.params.id } });
  if (!event) {
    return res.status(404).json({ message: 'unknown event' });
  }
  return res.json(event);
});

