import { Router } from 'express';

// Mounted under /internal by server.ts; the load balancer and the deploy
// dashboard are the only consumers, so responses stay intentionally tiny
// and schema-free.

export const metrics = Router();

const startedAt = Date.now();

// Liveness probe for the load balancer. Must not touch the database: the
// balancer treats any non-200 as instance-down.
metrics.get('/healthz', (_req, res) => {
  return res.json({ ok: true });
});

// Readiness: uptime + build metadata for the deploy dashboard.
metrics.get('/readyz', (_req, res) => {
  return res.json({
    ok: true,
    uptimeSecs: Math.floor((Date.now() - startedAt) / 1000),
    build: process.env.BUILD_SHA ?? 'dev',
  });
});

// Static instance metadata, used by the fleet screen grouping.
metrics.get('/instance', (_req, res) => {
  return res.json({
    region: process.env.DEPLOY_REGION ?? 'local',
    build: process.env.BUILD_SHA ?? 'dev',
  });
});

