import { Router } from 'express';
import { Prisma } from '@prisma/client';
import { prisma } from './prisma-client';

export const usage = Router();

interface CacheEntry {
  value: unknown;
  expiresAt: number;
}

const rollupCache = new Map<string, CacheEntry>();
const TTL_MS = 60_000;

function readCache(key: string): unknown {
  const hit = rollupCache.get(key);
  if (!hit || hit.expiresAt < Date.now()) {
    rollupCache.delete(key);
    return null;
  }
  return hit.value;
}

// The billing widget polls this endpoint every 5 s while the billing screen
// is open, and it appends `_=<epoch-ms>` to every request URL to defeat
// browser caching. The 60 s server-side cache is what keeps the scan below
// off the primary: it reads ~1.2M meter_readings rows for a large org
// (~700 ms).
usage.get('/orgs/:orgId/usage', async (req, res) => {
  const key = req.params.orgId;
  const cached = readCache(key);
  if (cached) {
    return res.json(cached);
  }
  const rollup = await prisma.$queryRaw(Prisma.sql`
    SELECT resource, sum(quantity)::float AS used
    FROM meter_readings
    WHERE org_id = ${req.params.orgId}
      AND read_at > now() - make_interval(days => 30)
    GROUP BY resource
  `);
  rollupCache.set(key, { value: rollup, expiresAt: Date.now() + TTL_MS });
  return res.json({ rollup });
});

