import { createHmac } from 'node:crypto';
import { Router } from 'express';
import { prisma } from './prisma-client';

export const webhooks = Router();

function signPayload(secret: string, body: string): string {
  return createHmac('sha256', secret).update(body).digest('hex');
}

// POST /orgs/:orgId/subscriptions — register a webhook subscription.
webhooks.post('/orgs/:orgId/subscriptions', async (req, res) => {
  const url = String(req.body.url ?? '');
  if (!/^https:\/\//.test(url)) {
    return res.status(422).json({ message: 'subscription url must be https' });
  }
  const sub = await prisma.webhookSubscription.create({
    data: { orgId: req.params.orgId, url, active: true },
  });
  return res.status(201).json({ id: sub.id });
});

// GET /orgs/:orgId/subscriptions — list registered subscriptions.
webhooks.get('/orgs/:orgId/subscriptions', async (req, res) => {
  const subs = await prisma.webhookSubscription.findMany({
    where: { orgId: req.params.orgId },
    select: { id: true, url: true, active: true },
  });
  return res.json({ subscriptions: subs });
});

