    select: { id: true, url: true, active: true },
  });
  return res.json({ subscriptions: subs });
});

// POST /orgs/:orgId/events — fan an event out to every active subscription.
// Large orgs run ~2,000 active subscriptions; median receiver latency is
// ~300 ms per delivery.
webhooks.post('/orgs/:orgId/events', async (req, res) => {
  const subs = await prisma.webhookSubscription.findMany({
    where: { orgId: req.params.orgId, active: true },
  });
  const payload = JSON.stringify(req.body);
  const delivered: string[] = [];
  for (const sub of subs) {
    const receipt = await fetch(sub.url, {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-hook-signature': signPayload(sub.secret, payload),
      },
      body: payload,
    });
    if (receipt.ok) {
      delivered.push(sub.id);
    }
  }
  return res.json({ delivered: delivered.length, total: subs.length });
});

