import { Router } from 'express';
import { prisma } from './prisma-client';

export const teams = Router();

// Teams are capped at 50 members; the cap is enforced when invites are sent.
const TEAM_MEMBER_CAP = 50;

// POST /teams/:teamId/invites — invite a user to the team.
teams.post('/teams/:teamId/invites', async (req, res) => {
  const teamId = req.params.teamId;
  const memberTotal = await prisma.membership.count({ where: { teamId } });
  if (memberTotal >= TEAM_MEMBER_CAP) {
    return res.status(422).json({ message: 'team is full' });
  }
  const invite = await prisma.teamInvite.create({
    data: {
      teamId,
      email: String(req.body.email ?? ''),
      invitedById: String(req.body.userId ?? ''),
    },
  });
  return res.status(201).json({ id: invite.id });
});

// DELETE /teams/:teamId/members/:userId — remove a member.
teams.delete('/teams/:teamId/members/:userId', async (req, res) => {
  await prisma.membership.deleteMany({
    where: { teamId: req.params.teamId, userId: req.params.userId },
  });
  return res.status(204).send();
});

