import { Router } from 'express';
import { prisma } from './prisma-client';

export const settings = Router();

interface OrgSettings {
  orgId: string;
  locale: string;
  weekStart: number;
  features: Record<string, boolean>;
}

function serialize(rowIn: {
  orgId: string;
  locale: string;
  weekStart: number;
  features: unknown;
}): OrgSettings {
  return {
    orgId: rowIn.orgId,
    locale: rowIn.locale,
    weekStart: rowIn.weekStart,
    features: (rowIn.features ?? {}) as Record<string, boolean>,
  };
}

// GET /orgs/:orgId/settings — read the org's settings document.
