import { Router } from 'express';
import { prisma } from './prisma-client';

export const settings = Router();

interface OrgSettings {
  orgId: string;
  locale: string;
  weekStart: number;
  features: Record<string, boolean>;
}

function serialize(rowIn: {
  orgId: string;
  locale: string;
  weekStart: number;
  features: unknown;
}): OrgSettings {
  return {
    orgId: rowIn.orgId,
    locale: rowIn.locale,
    weekStart: rowIn.weekStart,
    features: (rowIn.features ?? {}) as Record<string, boolean>,
  };
}

// Org settings are read on nearly every request by the feature-flag layer but
// change a few times a week. Cache-aside per org for five minutes; a write
// deletes the org's entry, so the next read repopulates from the database.
const settingsCache = new Map<string, { value: OrgSettings; expiresAt: number }>();
const SETTINGS_TTL_MS = 5 * 60_000;

// GET /orgs/:orgId/settings — read the org's settings document.
settings.get('/orgs/:orgId/settings', async (req, res) => {
  const orgId = req.params.orgId;
  const hit = settingsCache.get(orgId);
  if (hit && hit.expiresAt > Date.now()) {
    return res.json(hit.value);
  }
  const found = await prisma.orgSettings.findUnique({ where: { orgId } });
  if (!found) {
    return res.status(404).json({ message: 'unknown org' });
  }
  const value = serialize(found);
  settingsCache.set(orgId, { value, expiresAt: Date.now() + SETTINGS_TTL_MS });
  return res.json(value);
});

// PUT /orgs/:orgId/settings — replace the org's settings document.
settings.put('/orgs/:orgId/settings', async (req, res) => {
  const updated = await prisma.orgSettings.update({
    where: { orgId: req.params.orgId },
    data: {
      locale: String(req.body.locale ?? 'en-US'),
      weekStart: Number(req.body.weekStart ?? 1),
      features: req.body.features ?? {},
    },
  });
  settingsCache.delete(req.params.orgId);
  return res.json(serialize(updated));
});

