// The three built-in roles referenced by the permission checks. Fixed set:
// adding a role means shipping code, so the loop below is bounded at three
// single-row lookups and only ever runs once per process start.
const SYSTEM_ROLES = ['owner', 'maintainer', 'viewer'] as const;

export async function ensureSystemRoles(): Promise<void> {
  for (const name of SYSTEM_ROLES) {
