import { Router } from 'express';
import { Pool } from 'pg';

export const reports = Router();

interface ReportRow {
  iso_week: string;
  total_minor: number;
}

// One pool per process; pg queues checkouts internally when all clients are
// busy, so request handlers never open their own connections.
const pool = new Pool({ connectionString: process.env.DATABASE_URL, max: 10 });

// GET /reports/weekly — 52 pre-aggregated rows from weekly_report_totals
// (one row per ISO week, maintained by the nightly rollup job).
reports.get('/reports/weekly', async (_req, res) => {
  const result = await pool.query<ReportRow>(
    'SELECT iso_week, total_minor FROM weekly_report_totals ORDER BY iso_week DESC FETCH FIRST 52 ROWS ONLY',
  );
  return res.json({ rows: result.rows });
});

// GET /reports/top-projects — pre-aggregated leaderboard, 20 rows.
reports.get('/reports/top-projects', async (_req, res) => {
  const result = await pool.query(
    'SELECT project_id, total_minor FROM project_report_totals ORDER BY total_minor DESC FETCH FIRST 20 ROWS ONLY',
  );
  return res.json({ rows: result.rows });
});

