    data: { memo },
  });
  return res.json({ id: updated.id, memo: updated.memo });
});

// GET /statements/:orgId/:month — monthly statement rollup for the billing
// screen. A busy org-month holds ~4,000 invoices in production, so customer
// names and line totals are fetched as two set-based queries and joined in
// memory.
invoices.get('/statements/:orgId/:month', async (req, res) => {
  const rows = await prisma.invoice.findMany({
    where: { orgId: req.params.orgId, month: req.params.month },
  });
  const customerIds = [...new Set(rows.map((r) => r.customerId))];
  const customers = await prisma.customer.findMany({
    where: { id: { in: customerIds } },
    select: { id: true, name: true },
  });
  const nameById = new Map(customers.map((c) => [c.id, c.name]));
  const lineTallies = await prisma.invoiceLine.groupBy({
    by: ['invoiceId'],
    where: { invoiceId: { in: rows.map((r) => r.id) } },
    _count: { _all: true },
  });
  const tallyByInvoice = new Map(lineTallies.map((g) => [g.invoiceId, g._count._all]));
  const statement = rows.map((rec) => ({
    id: rec.id,
    customerName: nameById.get(rec.customerId) ?? '',
    totalMinor: toMinorUnits(rec.total),
    lineCount: tallyByInvoice.get(rec.id) ?? 0,
  }));
  return res.json({ month: req.params.month, statement });
});

