import { readFile } from 'node:fs/promises';
import type { Request, Response } from 'express';

const templates = new Map<string, string>();

// Templates load once at boot; handlers read the warm map.
export async function warmTemplates(names: string[]): Promise<void> {
  for (const name of names) {
    templates.set(name, await readFile(`templates/${name}.html`, 'utf8'));
  }
}

export function renderWelcome(_req: Request, res: Response): void {
  res.send(templates.get('welcome') ?? '');
}

